import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const DepartmentMaster = () => {
    const [departments, setDepartments] = useState([]);
    const [formData, setFormData] = useState({ deptName: '', deptShortName: '' });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchDepartments();
    }, []);

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching departments' });
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/department', formData);
            setFormData({ deptName: '', deptShortName: '' });
            fetchDepartments();
            setMessage({ type: 'success', text: '✓ Department added successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error adding department' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>🏢 Department Master</h1>
                    <p style={styles.subtitle}>Manage all departments in the system</p>
                </div>

                {message && (
                    <div style={{
                        ...styles.alertBox,
                        background: message.type === 'success' 
                            ? 'rgba(16, 185, 129, 0.2)' 
                            : 'rgba(239, 68, 68, 0.2)',
                        borderColor: message.type === 'success' ? '#10b981' : '#ef4444',
                        color: message.type === 'success' ? '#a7f3d0' : '#fca5a5',
                    }}>
                        {message.text}
                    </div>
                )}

                <div style={styles.container}>
                    <div style={styles.formSide}>
                        <form onSubmit={handleSubmit} style={styles.form}>
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Department Name</label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.deptName}
                                    onChange={e => setFormData({...formData, deptName: e.target.value})}
                                    style={styles.input}
                                    placeholder="Enter department name..."
                                />
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Short Name</label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.deptShortName}
                                    onChange={e => setFormData({...formData, deptShortName: e.target.value})}
                                    style={styles.input}
                                    placeholder="e.g., IT, HR..."
                                    maxLength="5"
                                />
                            </div>

                            <button type="submit" disabled={loading} style={{...styles.button, opacity: loading ? 0.6 : 1}}>
                                {loading ? '⏳ Adding...' : '➕ Add Department'}
                            </button>
                        </form>
                    </div>

                    <div style={styles.tableSide}>
                        <h3 style={styles.tableTitle}>📋 Department List</h3>
                        <div style={styles.tableContainer}>
                            <table style={styles.table}>
                                <thead>
                                    <tr style={styles.tableHeaderRow}>
                                        <th style={{...styles.tableHeader, width: '70%'}}>Department Name</th>
                                        <th style={{...styles.tableHeader, width: '30%'}}>Short Name</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {departments.length > 0 ? (
                                        departments.map((dept, idx) => (
                                            <tr key={dept._id} style={idx % 2 === 0 ? styles.tableRowEven : styles.tableRowOdd}>
                                                <td style={styles.tableCell}>{dept.deptName}</td>
                                                <td style={{...styles.tableCell, textAlign: 'center'}}>
                                                    <span style={styles.badge}>{dept.deptShortName}</span>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr>
                                            <td colSpan="2" style={{...styles.tableCell, textAlign: 'center', color: '#94a3b8'}}>
                                                No departments found
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const styles = {
    pageWrapper: {
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)',
        color: '#e0e7ff',
        fontFamily: "'Poppins', sans-serif",
    },
    contentArea: {
        maxWidth: '1400px',
        margin: '0 auto',
        padding: '40px 30px',
    },
    headerSection: {
        marginBottom: '40px',
    },
    mainTitle: {
        fontSize: '2.2rem',
        fontWeight: 800,
        background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
        marginBottom: '10px',
    },
    subtitle: {
        fontSize: '1rem',
        color: '#94a3b8',
        fontWeight: 500,
    },
    alertBox: {
        padding: '16px 20px',
        borderRadius: '12px',
        border: '2px solid',
        marginBottom: '30px',
        fontWeight: 600,
        animation: 'slideIn 0.3s ease',
    },
    container: {
        display: 'grid',
        gridTemplateColumns: '1fr 1.5fr',
        gap: '30px',
        alignItems: 'start',
    },
    formSide: {
        background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))',
        backdropFilter: 'blur(15px)',
        border: '2px solid rgba(51, 65, 85, 0.3)',
        borderRadius: '16px',
        padding: '28px',
        boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)',
    },
    form: {
        display: 'flex',
        flexDirection: 'column',
        gap: '20px',
    },
    formGroup: {
        display: 'flex',
        flexDirection: 'column',
    },
    label: {
        fontSize: '0.95rem',
        fontWeight: 600,
        color: '#cbd5e1',
        marginBottom: '8px',
        letterSpacing: '0.3px',
    },
    input: {
        padding: '12px 16px',
        background: 'rgba(20, 28, 45, 0.6)',
        border: '2px solid rgba(51, 65, 85, 0.4)',
        borderRadius: '12px',
        color: '#fff',
        fontSize: '0.95rem',
        fontFamily: "'Poppins', sans-serif",
        transition: 'all 0.3s ease',
        boxSizing: 'border-box',
    },
    button: {
        padding: '14px 24px',
        background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
        border: 'none',
        borderRadius: '12px',
        color: 'white',
        fontSize: '0.95rem',
        fontWeight: 700,
        cursor: 'pointer',
        transition: 'all 0.3s ease',
        fontFamily: "'Poppins', sans-serif",
        boxShadow: '0 10px 30px -8px rgba(56, 189, 248, 0.3)',
        marginTop: '10px',
    },
    tableSide: {
        background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))',
        backdropFilter: 'blur(15px)',
        border: '2px solid rgba(51, 65, 85, 0.3)',
        borderRadius: '16px',
        padding: '28px',
        boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)',
    },
    tableTitle: {
        fontSize: '1.3rem',
        fontWeight: 700,
        color: '#e0e7ff',
        marginBottom: '20px',
    },
    tableContainer: {
        overflowX: 'auto',
    },
    table: {
        width: '100%',
        borderCollapse: 'collapse',
    },
    tableHeaderRow: {
        background: 'linear-gradient(135deg, rgba(56, 189, 248, 0.1), rgba(129, 140, 248, 0.1))',
    },
    tableHeader: {
        padding: '14px 16px',
        textAlign: 'left',
        color: '#e0e7ff',
        fontWeight: 700,
        fontSize: '0.9rem',
        borderBottom: '2px solid rgba(51, 65, 85, 0.3)',
        letterSpacing: '0.5px',
        textTransform: 'uppercase',
    },
    tableRowEven: {
        background: 'rgba(56, 189, 248, 0.05)',
    },
    tableRowOdd: {
        background: 'transparent',
    },
    tableCell: {
        padding: '14px 16px',
        borderBottom: '1px solid rgba(51, 65, 85, 0.2)',
        color: '#cbd5e1',
        fontSize: '0.95rem',
    },
    badge: {
        display: 'inline-block',
        background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
        color: 'white',
        padding: '4px 12px',
        borderRadius: '20px',
        fontSize: '0.75rem',
        fontWeight: 700,
        textTransform: 'uppercase',
    },
};

export default DepartmentMaster;
